parameters.jsCode:
const item = $input.first();
const payloadBody = item?.json.body || {};

const errors = [];
const now = new Date().toISOString();

const normalizeString = (value) =>
  typeof value === 'string' ? value.trim() : '';

const isValidEmail = (email) =>
  /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

const isValidUrl = (url) => {
  const urlRegex = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
  return urlRegex.test(url);
};


const companyName = normalizeString(payloadBody.companyName);
const firstName = normalizeString(payloadBody.firstName);
const lastName = normalizeString(payloadBody.lastName);
const email = normalizeString(payloadBody.email).toLowerCase();
const phone = normalizeString(payloadBody.phone);
const website = normalizeString(payloadBody.website);
const serviceTier = normalizeString(payloadBody.serviceTier);
const notes = normalizeString(payloadBody.notes);

const allowedTiers = new Set([
  'Basic',
  'Professional',
  'Enterprise'
]);


if (!companyName) errors.push('companyName is required');
if (!firstName) errors.push('firstName is required');
if (!lastName) errors.push('lastName is required');

if (!email || !isValidEmail(email)) {
  errors.push('A valid email is required');
}

if (!website || !isValidUrl(website)) {
  errors.push('A valid website URL is required');
}

if (!allowedTiers.has(serviceTier)) {
  errors.push(
    'serviceTier must be one of: Basic, Professional, Enterprise'
  );
}


if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        status: 'validation_failed',
        errors,
        timestamp: now
      }
    }
  ];
}


return [
  {
    json: {
      success: true,
      source: 'webhook',
      company_name: companyName,
      contact_first_name: firstName,
      contact_last_name: lastName,
      contact_full_name: `${firstName} ${lastName}`,
      email,
      phone,
      website,
      service_tier: serviceTier,
      notes,
      status: 'validated',
      created_at: now,
      updated_at: now
    }
  }
];

const item = $input.first();
const data = item?.json || {};

const now = new Date();
const year = now.getFullYear();
const randomSequence = Math.floor(1000 + Math.random() * 9000);

return [
  {
    json: {
      ...data,
      client_ref: `NOA-${year}-${randomSequence}`,
      onboarding_date: now.toISOString().split('T')[0],
      updated_at: now.toISOString()
    }
  }
];

const response = $input.first() ? $input.first().json : {};
const prev = $('Generate Client Reference').first().json;

const statusCode = response && response.statusCode ? response.statusCode : null;
const body = response && response.body ? response.body : {};
const company = body && body.data ? body.data : null;
const apiErrors = body && Array.isArray(body.errors) ? body.errors : [];

let enrichment = {
  industry: 'Unknown',
  company_size: 'medium',
  location: 'Unknown',
  logo: '',
  enrichment_source: 'fallback',
  enrichment_error: null
};

if (apiErrors.length > 0) {
  enrichment.enrichment_error = apiErrors
    .map(function (err) {
      const code = err && (err.code || err.id) ? (err.code || err.id) : 'unknown';
      const details = err && err.details ? err.details : 'Unknown error';
      return code + ': ' + details;
    })
    .join('; ');
}

if (company && typeof company === 'object') {
  let industry = 'Unknown';

  if (company.category) {
    industry =
      company.category.industry ||
      company.category.industryGroup ||
      company.category.sector ||
      'Unknown';
  }

  if (
    industry === 'Unknown' &&
    Array.isArray(company.techCategories) &&
    company.techCategories.length > 0
  ) {
    industry = company.techCategories[0];
  }

  let companySize = 'medium';
  const employees =
    company.metrics && typeof company.metrics.employees === 'number'
      ? company.metrics.employees
      : null;

  if (employees !== null) {
    if (employees < 50) {
      companySize = 'small';
    } else if (employees < 250) {
      companySize = 'medium';
    } else {
      companySize = 'large';
    }
  }

  let location = 'Unknown';

  if (company.location) {
    location = company.location;
  } else if (company.geo) {
    location =
      company.geo.city ||
      company.geo.state ||
      company.geo.country ||
      'Unknown';
  }

  enrichment = {
    industry: industry,
    company_size: companySize,
    location: location,
    logo: company.logo || '',
    enrichment_source: 'hunter-company-enrichment',
    enrichment_error: null
  };
}

return [
  {
    json: {
      ...prev,
      ...enrichment,
      enrichment_status_code: statusCode,
      enriched_domain: company && company.domain ? company.domain : (prev.domain || ''),
      enriched_company_name:
        company && (company.name || company.legalName)
          ? (company.name || company.legalName)
          : prev.company_name,
      status: 'enriched',
      updated_at: new Date().toISOString()
    }
  }
];

const data = $json;

const tierDescriptions = {
  Basic: 'Basic onboarding with standard setup and essential support.',
  Professional: 'Professional onboarding with guided setup, configuration support, and faster coordination.',
  Enterprise: 'Enterprise onboarding with dedicated coordination, advanced planning, and stakeholder alignment.'
};

const tierNextSteps = {
  Basic: [
    'Review welcome information',
    'Confirm primary contact details',
    'Start standard onboarding process'
  ],
  Professional: [
    'Review welcome information',
    'Confirm account and contact details',
    'Schedule onboarding session',
    'Prepare integration requirements'
  ],
  Enterprise: [
    'Review welcome information',
    'Confirm account and stakeholder contacts',
    'Schedule discovery workshop',
    'Review security and integration requirements',
    'Assign onboarding owner'
  ]
};

const tier = data.service_tier || 'Basic';
const steps = tierNextSteps[tier] || tierNextSteps.Basic;
const description = tierDescriptions[tier] || tierDescriptions.Basic;

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Welcome - ${data.company_name}</title>
  <style>
    body {
      font-family: Segoe UI, Arial, sans-serif;
      max-width: 700px;
      margin: 40px auto;
      color: #1a1a2e;
      line-height: 1.6;
      padding: 0 24px;
    }
    .header {
      background: #1a1a2e;
      color: white;
      padding: 32px;
      border-radius: 12px 12px 0 0;
    }
    .content {
      border: 1px solid #ddd;
      border-top: none;
      padding: 24px;
      border-radius: 0 0 12px 12px;
    }
    .box {
      background: #f8f9fa;
      padding: 16px;
      border-radius: 8px;
      margin: 16px 0;
    }
    h1, h2 {
      margin-top: 0;
    }
    ul {
      padding-left: 20px;
    }
    .footer {
      margin-top: 24px;
      font-size: 12px;
      color: #666;
    }
  </style>
</head>
<body>
  <div class="header">
    <h1>Welcome to NOAVIA</h1>
    <p>Your onboarding has been prepared successfully.</p>
  </div>

  <div class="content">
    <div class="box">
      <p><strong>Client Reference:</strong> ${data.client_ref}</p>
      <p><strong>Company Name:</strong> ${data.company_name}</p>
      <p><strong>Contact Person:</strong> ${data.contact_full_name}</p>
      <p><strong>Email:</strong> ${data.email}</p>
      <p><strong>Phone:</strong> ${data.phone || 'N/A'}</p>
      <p><strong>Website:</strong> ${data.website}</p>
      <p><strong>Service Tier:</strong> ${data.service_tier}</p>
      <p><strong>Onboarding Date:</strong> ${data.onboarding_date}</p>
    </div>

    <h2>Service Description</h2>
    <p>${description}</p>

    <h2>Next Steps</h2>
    <ul>
      ${steps.map(step => `<li>${step}</li>`).join('')}
    </ul>

    <h2>Enrichment Summary</h2>
    <p><strong>Industry:</strong> ${data.industry || 'Unknown'}</p>
    <p><strong>Company Size:</strong> ${data.company_size || 'Unknown'}</p>
    <p><strong>Location:</strong> ${data.location || 'Unknown'}</p>

    ${data.notes ? `<h2>Special Requirements</h2><p>${data.notes}</p>` : ''}

    <div class="footer">
      NOAVIA GmbH · AI Automation Company · Berlin, Germany<br>
      Auto-generated on ${data.onboarding_date} · Ref: ${data.client_ref}
    </div>
  </div>
</body>
</html>`;

return {
  json: {
    ...data,
    welcome_html: html,
    doc_filename: `Welcome_${data.company_name.replace(/[^a-zA-Z0-9]/g, '_')}_${data.client_ref}.html`,
    status: 'document-ready'
  }
};

const sourceRows = $input.all().map(item => item.json);


const fieldMap = {
  'Kundennr': 'customer_number',
  'Firma': 'company_name',
  'Ansprechpartner': 'contact_person',
  'E-Mail': 'erp_email',
  'Telefon': 'erp_phone',
  'Straße': 'street',
  'PLZ': 'postal_code',
  'Ort': 'city',
  'Land': 'country',
  'Branche': 'industry',
  'Kundenseit': 'customer_since',
  'Umsatz_2025': 'revenue_2025',
  'Zahlungsziel': 'payment_terms',
  'Bemerkung': 'notes'
};

const imported = [];
const skipped = [];
const seenNumbers = new Set();
const seenCompanies = new Set();

for (let i = 0; i < sourceRows.length; i++) {
  const raw = sourceRows[i] || {};

  const record = {
    erp_status: 'imported-from-erp'
  };

  for (const [de, en] of Object.entries(fieldMap)) {
    const value = raw[de];
    record[en] = value === undefined || value === null ? '' : String(value).trim();
  }

  const normalizedCompanyName = (record.company_name || '').toLowerCase();

  if (!record.company_name) {
    skipped.push({
      row: i + 1,
      kundennr: raw.Kundennr || 'N/A',
      reason: 'missing company name (Firma leer)'
    });
    continue;
  }

  if (!record.customer_number) {
    skipped.push({
      row: i + 1,
      company: record.company_name,
      reason: 'missing customer number (Kundennr fehlt)'
    });
    continue;
  }

  if (seenNumbers.has(record.customer_number)) {
    skipped.push({
      row: i + 1,
      kundennr: record.customer_number,
      company: record.company_name,
      reason: `duplicate Kundennr: ${record.customer_number}`
    });
    continue;
  }

  if (seenCompanies.has(normalizedCompanyName)) {
    skipped.push({
      row: i + 1,
      kundennr: record.customer_number,
      company: record.company_name,
      reason: `duplicate company name: ${record.company_name}`
    });
    continue;
  }

  seenNumbers.add(record.customer_number);
  seenCompanies.add(normalizedCompanyName);
  imported.push(record);
}

return [
  {
    json: {
      erp_import: {
        imported,
        skipped,
        summary: {
          total_rows: sourceRows.length,
          imported_count: imported.length,
          skipped_count: skipped.length
        }
      },
      status: 'erp-processed'
    }
  }
];

const BINARY_FIELD = 'data'; 
const buf = await this.helpers.getBinaryDataBuffer(0, BINARY_FIELD);


const csvText = buf
  .toString('latin1')
  .replace(/^\uFEFF/, '')     
  .replace(/\r\n/g, '\n') 
  .replace(/\r/g, '\n');

const lines = csvText.split('\n').filter(l => l.trim() !== '');
if (lines.length < 2) {
  throw new Error(`CSV looks empty or has no data rows (lines=${lines.length}).`);
}

function parseSemicolonLine(line) {
  const out = [];
  let cur = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    const next = line[i + 1];

    if (ch === '"') {
      if (inQuotes && next === '"') {
        cur += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (ch === ';' && !inQuotes) {
      out.push(cur.trim());
      cur = '';
      continue;
    }

    cur += ch;
  }

  out.push(cur.trim());
  return out;
}

const headers = parseSemicolonLine(lines[0]);
if (!headers.length) {
  throw new Error('Header row could not be parsed.');
}

const items = [];

for (let r = 1; r < lines.length; r++) {
  const values = parseSemicolonLine(lines[r]);

  if (values.every(v => v === '')) continue;

  const row = {};
  for (let c = 0; c < headers.length; c++) {
    const key = headers[c] || `column_${c + 1}`;
    row[key] = values[c] ?? '';
  }

  items.push({ json: row });
}

if (!items.length) {
  throw new Error('No data rows were parsed from the CSV file.');
}

console.log(`Parsed ERP rows: ${items.length}, headers: ${headers.length}`);

return items;

